import{_ as a,o,c as r,a0 as t}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"ADR-0012: ADR-012: Escopo NEXUS para intraclinica-ng","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0012-intraclinica-nexus-scope.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0012-intraclinica-nexus-scope.md","lastUpdated":1782593311000}'),i={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0012-intraclinica-nexus-scope.md"};function n(l,e,s,d,c,u){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="adr-0012-adr-012-escopo-nexus-para-intraclinica-ng" tabindex="-1">ADR-0012: ADR-012: Escopo NEXUS para intraclinica-ng <a class="header-anchor" href="#adr-0012-adr-012-escopo-nexus-para-intraclinica-ng" aria-label="Permalink to &quot;ADR-0012: ADR-012: Escopo NEXUS para intraclinica-ng&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Accepted</p><h2 id="context-detailed-analysis" tabindex="-1">Context / Detailed Analysis <a class="header-anchor" href="#context-detailed-analysis" aria-label="Permalink to &quot;Context / Detailed Analysis&quot;">​</a></h2><p><strong>Contexto:</strong> Decisão sobre até qual ponto do pipeline NEXUS operar no projeto intraclinica-ng, dado que o projeto tem escopo e deadline reais.</p><hr><h2 id="contexto" tabindex="-1">Contexto <a class="header-anchor" href="#contexto" aria-label="Permalink to &quot;Contexto&quot;">​</a></h2><p>O intraclinica-ng é o projeto Angular que o NEXUS está indexando como caso de uso primário. O pipeline completo (L0→L6, T1→T5) é um laboratório em evolução — mas o intraclinica precisa de valor concreto agora, não de experimentação indefinida.</p><p>A decisão é: <strong>até onde ir</strong> sem comprometer estabilidade e utilidade real.</p><hr><h2 id="decisao-operar-ate-l4-cross-blob" tabindex="-1">Decisão: Operar até L4 cross-blob <a class="header-anchor" href="#decisao-operar-ate-l4-cross-blob" aria-label="Permalink to &quot;Decisão: Operar até L4 cross-blob&quot;">​</a></h2><h3 id="por-que-nao-parar-em-l2" tabindex="-1">Por que não parar em L2 <a class="header-anchor" href="#por-que-nao-parar-em-l2" aria-label="Permalink to &quot;Por que não parar em L2&quot;">​</a></h3><p>L2 (semântico por chunk) já funciona e já produz <code>nexus_query</code> útil. Mas chunks isolados não capturam o propósito de um módulo Angular — um <code>service</code>, um <code>store</code>, um <code>guard</code> só fazem sentido em relação aos outros. L3 por blob é o mínimo para que um agente entenda <em>por que</em> um arquivo existe.</p><h3 id="por-que-ir-ate-l4" tabindex="-1">Por que ir até L4 <a class="header-anchor" href="#por-que-ir-ate-l4" aria-label="Permalink to &quot;Por que ir até L4&quot;">​</a></h3><p>O intraclinica-ng tem padrões arquiteturais que emergem cross-arquivo:</p><ul><li>Quais signals fluem entre quais componentes</li><li>Onde o estado é centralizado vs distribuído</li><li>Quais módulos têm acoplamento implícito</li></ul><p>L4 captura exatamente isso — invariantes que nenhum arquivo documenta sozinho. Para um agente que vai implementar features ou fazer refactoring seguro, L4 é a diferença entre &quot;encontrei o arquivo certo&quot; e &quot;entendo o contexto da mudança&quot;.</p><h3 id="por-que-nao-ir-alem-l5-l6-agora" tabindex="-1">Por que não ir além (L5/L6 agora) <a class="header-anchor" href="#por-que-nao-ir-alem-l5-l6-agora" aria-label="Permalink to &quot;Por que não ir além (L5/L6 agora)&quot;">​</a></h3><p>L5 (hipóteses falsificáveis) e L6 (modelo mental) requerem L3 e L4 maduros e bem povoados. Implementar antes disso produz especulações sem base sólida. Além disso, o custo de Sonnet/Opus em volume alto não é justificável antes de validar que L3/L4 entregam valor real.</p><hr><h2 id="pipeline-para-intraclinica-ng" tabindex="-1">Pipeline para intraclinica-ng <a class="header-anchor" href="#pipeline-para-intraclinica-ng" aria-label="Permalink to &quot;Pipeline para intraclinica-ng&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>O que faz</th><th>Modelo</th><th>Status</th></tr></thead><tbody><tr><td>L0</td><td>Chunks brutos</td><td>—</td><td>✅ Funcionando</td></tr><tr><td>L1</td><td>AST por blob</td><td>ast-grep</td><td>✅ Funcionando</td></tr><tr><td>L2</td><td>Semântico por chunk</td><td>Gemini Flash (proxy)</td><td>✅ Funcionando (35% completo)</td></tr><tr><td>L3</td><td>Propósito por blob</td><td>Mistral local</td><td>🔲 A implementar</td></tr><tr><td>L4</td><td>Padrões cross-blob</td><td>Gemini Flash</td><td>🔲 Experimental</td></tr><tr><td>L5+</td><td>Hipóteses / modelo mental</td><td>—</td><td>⏸ Não agora</td></tr></tbody></table><hr><h2 id="criterio-de-sucesso-f-full" tabindex="-1">Critério de Sucesso (F-full) <a class="header-anchor" href="#criterio-de-sucesso-f-full" aria-label="Permalink to &quot;Critério de Sucesso (F-full)&quot;">​</a></h2><p>O pipeline está &quot;completo o suficiente&quot; para o intraclinica quando:</p><ol><li><p><code>nexus_query(&quot;como o sistema gerencia estado no módulo de agendamento&quot;)</code> retorna contexto não-vazio com chunks L2 relevantes e pelo menos um L3 de blob relacionado.</p></li><li><p><code>nexus_repomap()</code> mapeia corretamente services, stores, guards e signals do módulo clínico principal.</p></li><li><p>Um agente consegue implementar uma feature simples (novo campo em formulário) usando apenas <code>nexus_query</code> + <code>nexus_repomap</code> — sem precisar ler arquivos manualmente.</p></li></ol><hr><h2 id="consequencias" tabindex="-1">Consequências <a class="header-anchor" href="#consequencias" aria-label="Permalink to &quot;Consequências&quot;">​</a></h2><ul><li>Prioridade imediata: completar enriquecimento L2 (hoje em 35%)</li><li>Depois: reformular <code>run_reflect</code> para L3 por blob com Mistral</li><li>Depois: prototipar L4 como job periódico sobre clusters de blobs relacionados</li><li><code>nexus_query</code> deve atualizar <code>last_accessed_at</code> para ativar decay temporal</li><li>L5/L6/T5 ficam no ADR-011 como especulação — revisitar após L4 validado</li></ul><hr><h2 id="referencias" tabindex="-1">Referências <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;Referências&quot;">​</a></h2><ul><li>ADR-010: Hierarquia de Levels e o Papel do Tempo</li><li>ADR-011: T5 — Espaço Algébrico (especulação futura)</li></ul>',32)])])}const h=a(i,[["render",n]]);export{m as __pageData,h as default};
